suggestions:
.modal__close {
  position: absolute;
  top: 15px;
  right: 15px;
  font-size: 2rem;
  line-height: 1;
  color: var(--color-text-secondary);
  background: none;
  border: none;
  cursor: pointer;
  transition: color var(--transition-fast);
}

.modal__close:hover {
  color: #fff;
}

.modal__close:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 2px;
  color: #fff;
}
